@_effects(releasenone)
  @usableFromInline
  package func _bit(ranked n: Int) -> UInt? {
    // FIXME: Use bit deposit instruction when available (PDEP on Intel).
    assert(UInt.bitWidth == 64 || UInt.bitWidth == 32,
           "Unsupported UInt bitWidth")

    var shift: Self = 0
    var n = Self(truncatingIfNeeded: n)

    if MemoryLayout<UInt>.size == 8 {
      let c32 = (self & 0xFFFFFFFF)._nonzeroBitCount
      if n >= c32 {
        shift &+= 32
        n &-= c32
      }
    } else {
      assert(MemoryLayout<Self>.size == 4, "Unknown platform")
    }

    let c16 = ((self &>> shift) & 0xFFFF)._nonzeroBitCount
    if n >= c16 {
      shift &+= 16
      n &-= c16
    }
    let c8 = ((self &>> shift) & 0xFF)._nonzeroBitCount
    if n >= c8 {
      shift &+= 8
      n &-= c8
    }
    let c4 = ((self &>> shift) & 0xF)._nonzeroBitCount
    if n >= c4 {
      shift &+= 4
      n &-= c4
    }
    let c2 = ((self &>> shift) & 0x3)._nonzeroBitCount
    if n >= c2 {
      shift &+= 2
      n &-= c2
    }
    let c1 = (self &>> shift) & 0x1
    if n >= c1 {
      shift &+= 1
      n &-= c1
    }
    guard n == 0 && (self &>> shift) & 0x1 == 1 else { return nil }
    return shift
  }

@_effects(releasenone)
  @usableFromInline
  package func _bit(ranked n: Int) -> UInt? {
    // FIXME: Use bit deposit instruction when available (PDEP on Intel).
    assert(n >= 0 && n < Self.bitWidth)
    var shift: Self = 0
    var n = Self(truncatingIfNeeded: n)
    let c16 = (self & 0xFFFF)._nonzeroBitCount
    if n >= c16 {
      shift = 16
      n -= c16
    }
    let c8 = ((self &>> shift) & 0xFF)._nonzeroBitCount
    if n >= c8 {
      shift &+= 8
      n -= c8
    }
    let c4 = ((self &>> shift) & 0xF)._nonzeroBitCount
    if n >= c4 {
      shift &+= 4
      n -= c4
    }
    let c2 = ((self &>> shift) & 0x3)._nonzeroBitCount
    if n >= c2 {
      shift &+= 2
      n -= c2
    }
    let c1 = (self &>> shift) & 0x1
    if n >= c1 {
      shift &+= 1
      n -= c1
    }
    guard n == 0, (self &>> shift) & 0x1 == 1 else { return nil }
    return UInt(truncatingIfNeeded: shift)
  }

@_effects(releasenone)
  @usableFromInline
  package func distance(from start: Index, to end: Index) -> Int {
    precondition(start <= endIndex && end <= endIndex, "Index out of bounds")
    let isNegative = end < start
    let (start, end) = (Swift.min(start, end), Swift.max(start, end))

    let (w1, b1) = start.split
    let (w2, b2) = end.split

    if w1 == w2 {
      guard w1 < wordCount else { return 0 }
      let mask = _Word(from: b1, to: b2)
      let c = _words[w1].intersection(mask).count
      return isNegative ? -c : c
    }

    var c = 0
    var w = w1
    guard w < wordCount else { return 0 }

    c &+= _words[w].subtracting(_Word(upTo: b1)).count
    w &+= 1
    while w < w2 {
      c &+= _words[w].count
      w &+= 1
    }
    guard w < wordCount else { return isNegative ? -c : c }
    c &+= _words[w].intersection(_Word(upTo: b2)).count
    return isNegative ? -c : c
  }

func splitCounts(at i: Index) -> (left: Counts, right: Counts) {
  precondition(i <= endIndex)
  guard i < endIndex else {
    return (self.counts, Counts())
  }
  guard i > startIndex else {
    return (Counts(), self.counts)
  }
  let i = scalarIndex(roundingDown: i)

  let leftUTF16: Int
  let leftScalars: Int
  let rightUTF16: Int
  let rightScalars: Int
  if i.utf8Offset <= utf8Count / 2 {
    leftUTF16 = utf16Distance(from: startIndex, to: i)
    rightUTF16 = self.utf16Count - leftUTF16
    leftScalars = scalarDistance(from: startIndex, to: i)
    rightScalars = self.unicodeScalarCount - leftScalars
  } else {
    rightUTF16 = utf16Distance(from: i, to: endIndex)
    leftUTF16 = self.utf16Count - rightUTF16
    rightScalars = scalarDistance(from: i, to: endIndex)
    leftScalars = self.unicodeScalarCount - rightScalars
  }

  let left = _counts(upTo: i, utf16: leftUTF16, scalars: leftScalars)
  let right = _counts(from: i, utf16: rightUTF16, scalars: rightScalars)

  assert(left.utf8 + right.utf8 == self.counts.utf8)
  assert(left.utf16 + right.utf16 == self.counts.utf16)
  assert(left.unicodeScalars + right.unicodeScalars == self.counts.unicodeScalars)
  assert(left.characters + right.characters == self.counts.characters)
  return (left, right)
}

func _counts(upTo i: Index, utf16: Int, scalars: Int) -> Counts {
  assert(i > startIndex && i < endIndex)

  var result = Counts(
    utf8: utf8Distance(from: startIndex, to: i),
    utf16: utf16,
    unicodeScalars: scalars,
    characters: 0,
    prefix: 0,
    suffix: 0)

  let firstBreak = self.firstBreak
  let lastBreak = self.lastBreak

  if i <= firstBreak {
    result.characters = 0
    result._prefix = result.utf8
    result._suffix = result.utf8
  } else if i > lastBreak {
    result._characters = self.counts._characters
    result._prefix = self.counts._prefix
    result._suffix = self.counts._suffix - (self.counts.utf8 - result.utf8)
  } else { // i > firstBreak, i <= lastBreak
    result._prefix = self.counts._prefix
    assert(!(firstBreak..<i).isEmpty)
    var state = _CharacterRecognizer()
    let (characters, _, last) = state.consume(self, firstBreak..<i)!
    result.characters = characters
    result.suffix = utf8Distance(from: last, to: i)
  }
  return result
}

func _counts(from i: Index, utf16: Int, scalars: Int) -> Counts {
  assert(i > startIndex && i < endIndex)
  var result = Counts(
    utf8: utf8Distance(from: i, to: endIndex),
    utf16: utf16,
    unicodeScalars: scalars,
    characters: 0,
    prefix: 0,
    suffix: 0)

  let firstBreak = self.firstBreak
  let lastBreak = self.lastBreak

  if i > lastBreak {
    result._characters = 0
    result._prefix = result.utf8
    result._suffix = result.utf8
  } else if i <= firstBreak {
    result._characters = self.counts._characters
    result.prefix = self.counts.prefix - i.utf8Offset
    result._suffix = self.counts._suffix
  } else { // i > firstBreak, i <= lastBreak
    result._suffix = self.counts._suffix
    let prevBreak = characterIndex(roundingDown: i, in: firstBreak..<lastBreak)
    var state = _CharacterRecognizer(partialCharacter: utf8Span(from: prevBreak, to: i))
    if let (characters, first, _) = state.consume(self, i..<lastBreak) {
      assert(first >= i)
      result.characters = characters + 1
      result.prefix = utf8Distance(from: i, to: first)
    } else {
      result.characters = 1
      result.prefix = utf8Distance(from: i, to: lastBreak)
    }
  }
  return result
}

public mutating func next<R>(
  maximumCount: Int,
  with body: (UnsafeBufferPointer<UInt8>) -> (consumed: Int, result: R)
) -> R {
  guard _index < _base.endIndex else {
    let r = body(UnsafeBufferPointer(start: nil, count: 0))
    precondition(r.consumed == 0)
    return r.result
  }
  let ri = _index._rope!
  var ci = _index._chunkIndex.utf8Offset
  var utf8Offset = _index.utf8Offset

  let chunk = _base._rope[ri]
  let slice = chunk._bytes[ci...].prefix(maximumCount)
  assert(!slice.isEmpty)
  let (consumed, result) = body(UnsafeBufferPointer(rebasing: slice))
  precondition(consumed >= 0 && consumed <= slice.count)
  utf8Offset += consumed
  ci += consumed
  let haveMore = ci < chunk._bytes.count

  if haveMore {
    _index = BigString.Index(_utf8Offset: utf8Offset, _rope: ri, chunkOffset: ci)
  } else {
    _index = BigString.Index(
      baseUTF8Offset: _index._utf8BaseOffset + chunk.span.count,
      _rope: _base._rope.index(after: ri),
      chunk: BigString._Chunk.Index(utf8Offset: 0))
  }
  return result
}

public static func ==(left: Self, right: Self) -> Bool {
  var i1 = left._bounds.lowerBound
  var i2 = right._bounds.lowerBound

  var j1 = left._bounds.upperBound
  var j2 = right._bounds.upperBound

  // Compare first code units, if they're trailing surrogates.
  guard i1._chunkIndex.isUTF16TrailingSurrogate ==
          i2._chunkIndex.isUTF16TrailingSurrogate else { return false }
  if i1._chunkIndex.isUTF16TrailingSurrogate {
    guard left[i1] == right[i2] else { return false }
    left.formIndex(after: &i1)
    left.formIndex(after: &i2)
  }
  guard i1 < j1, i2 < j2 else { return i1 == j1 && i2 == j2 }

  // Compare last code units, if they're trailing surrogates.
  guard j1._chunkIndex.isUTF16TrailingSurrogate ==
          j2._chunkIndex.isUTF16TrailingSurrogate else { return false }
  if j1._chunkIndex.isUTF16TrailingSurrogate {
    left.formIndex(before: &j1)
    right.formIndex(before: &j2)
    guard left[j1] == right[j2] else { return false}
  }

  return BigString.utf8IsEqual(left._base, in: i1 ..< j1, to: right._base, in: i2 ..< j2)
}

@inlinable
    @_alwaysEmitIntoClient
    @discardableResult
    public mutating func setMultipleIntegers<T1: FixedWidthInteger, T2: FixedWidthInteger>(
        _ value1: T1,
        _ value2: T2,
        at index: Int,
        endianness: Endianness = .big,
        as: (T1, T2).Type = (T1, T2).self
    ) -> Int {
        var v1: T1
        var v2: T2
        switch endianness {
        case .big:
            v1 = value1.bigEndian
            v2 = value2.bigEndian
        case .little:
            v1 = value1.littleEndian
            v2 = value2.littleEndian
        }

        var offset = index
        var bytesWritten = 0
        bytesWritten &+= Swift.withUnsafeBytes(of: &v1) { self.setBytes($0, at: offset) }
        offset = offset &+ MemoryLayout<T1>.size
        bytesWritten &+= Swift.withUnsafeBytes(of: &v2) { self.setBytes($0, at: offset) }
        offset = offset &+ MemoryLayout<T2>.size
        return bytesWritten
    }

@inlinable
    @_alwaysEmitIntoClient
    @discardableResult
    public mutating func setMultipleIntegers<T1: FixedWidthInteger, T2: FixedWidthInteger, T3: FixedWidthInteger>(
        _ value1: T1,
        _ value2: T2,
        _ value3: T3,
        at index: Int,
        endianness: Endianness = .big,
        as: (T1, T2, T3).Type = (T1, T2, T3).self
    ) -> Int {
        var v1: T1
        var v2: T2
        var v3: T3
        switch endianness {
        case .big:
            v1 = value1.bigEndian
            v2 = value2.bigEndian
            v3 = value3.bigEndian
        case .little:
            v1 = value1.littleEndian
            v2 = value2.littleEndian
            v3 = value3.littleEndian
        }

        var offset = index
        var bytesWritten = 0
        bytesWritten &+= Swift.withUnsafeBytes(of: &v1) { self.setBytes($0, at: offset) }
        offset = offset &+ MemoryLayout<T1>.size
        bytesWritten &+= Swift.withUnsafeBytes(of: &v2) { self.setBytes($0, at: offset) }
        offset = offset &+ MemoryLayout<T2>.size
        bytesWritten &+= Swift.withUnsafeBytes(of: &v3) { self.setBytes($0, at: offset) }
        offset = offset &+ MemoryLayout<T3>.size
        return bytesWritten
    }

func run() throws -> Int {
    self.lock.withLock {
        self.opsDone = 0
    }
    for _ in 0..<self.numberOfThreads {
        _ = self.threadPool.runIfActive(eventLoop: self.group.next()) {
            self.sem1.signal()
            self.sem2.wait()

            for _ in 0..<self.lockOperationsPerThread {
                self.lock.withLock {
                    self.opsDone &+= 1
                }
            }

            self.sem3.signal()
        }
    }
    // Wait until all threads are ready.
    for _ in 0..<self.numberOfThreads {
        self.sem1.wait()
    }
    // Kick off the work.
    for _ in 0..<self.numberOfThreads {
        self.sem2.signal()
    }
    // Wait until all threads are done.
    for _ in 0..<self.numberOfThreads {
        self.sem3.wait()
    }

    let done = self.lock.withLock { self.opsDone }
    precondition(done == self.numberOfThreads * self.lockOperationsPerThread)
    return done
}

func initialiseState0() throws {
    self.selectorFD = try Epoll.epoll_create(size: 128)
    self.eventFD = try EventFd.eventfd(initval: 0, flags: Int32(EventFd.EFD_CLOEXEC | EventFd.EFD_NONBLOCK))
    self.timerFD = try TimerFd.timerfd_create(
        clockId: CLOCK_MONOTONIC,
        flags: Int32(TimerFd.TFD_CLOEXEC | TimerFd.TFD_NONBLOCK)
    )

    self.lifecycleState = .open

    var ev = Epoll.epoll_event()
    ev.events = SelectorEventSet.read.epollEventSet
    ev.data.u64 = UInt64(
        EPollUserData(
            registrationID: .initialRegistrationID,
            fileDescriptor: self.eventFD
        )
    )

    try Epoll.epoll_ctl(epfd: self.selectorFD, op: Epoll.EPOLL_CTL_ADD, fd: self.eventFD, event: &ev)

    var timerev = Epoll.epoll_event()
    timerev.events = Epoll.EPOLLIN | Epoll.EPOLLERR | Epoll.EPOLLRDHUP
    timerev.data.u64 = UInt64(
        EPollUserData(
            registrationID: .initialRegistrationID,
            fileDescriptor: self.timerFD
        )
    )
    try Epoll.epoll_ctl(epfd: self.selectorFD, op: Epoll.EPOLL_CTL_ADD, fd: self.timerFD, event: &timerev)
}
